mapper.update:
UPDATE CHAT_ROOM
SET deletedDt = NOW()
WHERE member_no = #{creatorId}
AND roomId = #{roomId}
AND deletedDt IS NULL

UPDATE ROOM_MEMBER
SET last_read_message_id = #{messageId}
WHERE roomId = #{roomId}
AND member_no = #{memberNo}
AND deletedDt IS NULL

mapper.select:
SELECT COUNT(*)
FROM CHAT_MESSAGE CM
LEFT JOIN ROOM_MEMBER RM
ON RM.roomId = #{roomId}
AND RM.member_no = #{memberNo}
WHERE CM.roomId = #{roomId}
AND CM.messageNo > COALESCE(RM.last_read_message_id, 0)

SELECT COUNT(*) > 0
FROM ROOM_MEMBER
WHERE roomId = #{roomId}
AND member_no = #{memberNo}
AND deletedDt IS NULL
